/** Build Concept Row for tvpx_concept_pool */
function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const j = $json;
const ctx = j.ctx;
const now = new Date().toISOString();

const seed = `${ctx.trace_id}::${ctx.crawl_run_id}::${(j.bundle.fragment_ids||[]).join(',')}::${j.symbolic_tension.concept_thesis}`;
const conceptId = `tvpx_cp_${fnv1a(seed)}`;

const seriesDNA = {
  brand: 'The Velvet Paradox',
  abstraction_target: j.abstraction.abstraction_target,
  mechanisms: j.abstraction.abstraction_mechanisms || [],
  composition_bias: j.composition.framing_bias || '',
  focal_strategy: j.composition.focal_strategy || '',
  palette: {
    base: j.chromatic.base_palette || [],
    accent: j.chromatic.accent_palette || [],
    luminance: j.chromatic.luminance_behavior || ''
  },
  texture_stack: j.composition.texture_stack || [],
  atmosphere: j.chromatic.atmosphere_notes || ''
};

const guardrails = {
  anti_stock: true,
  avoid_cliches: ['teamwork','lightbulb','gears','handshake','generic office'],
  keep_representational: true,
  abstraction_band: [Number(ctx.target_abstraction_min||5.8), Number(ctx.target_abstraction_max||6.8)]
};

return [{
  json: {
    ctx: { ...ctx, concept_id: conceptId, root_concept_id: conceptId },
    concept: {
      concept_id: conceptId,
      trace_id: ctx.trace_id,
      origin_type: 'crawler',
      source_id: ctx.source_id,
      parent_concept_id: null,
      root_concept_id: conceptId,
      seed_fragment_ids_json: JSON.stringify(j.bundle.fragment_ids || []),
      concept_thesis: String(j.symbolic_tension.concept_thesis || '').trim(),
      symbolic_tension: String(j.symbolic_tension.symbolic_tension || '').trim(),
      material_anchor: String(j.symbolic_tension.material_anchor || '').trim(),
      spatial_directive: String(j.composition.foreground_midground_background || j.symbolic_tension.spatial_hint || '').trim(),
      palette_directive: JSON.stringify(j.chromatic || {}),
      texture_directive: JSON.stringify({ texture_stack: j.composition.texture_stack || [] }),
      abstraction_target: Number(j.abstraction.abstraction_target || 6.2),
      series_dna_json: JSON.stringify(seriesDNA),
      prompt_guardrails_json: JSON.stringify(guardrails),
      quality_score: Number(j.critic.score || 0),
      state: 'ready',
      lock_owner: '',
      lock_expires_at: '',
      used_count: 0,
      last_used_at: '',
      created_at: now,
      updated_at: now
    }
  }
}];

/** Build Reject Row From Critic */
const j = $json;
const ctx = j.ctx;
const now = new Date().toISOString();
return [{
  json: {
    ctx,
    reject: {
      reject_id: `tvpx_rej_${ctx.trace_id}_${now.replace(/[:.]/g,'')}`,
      trace_id: ctx.trace_id,
      stage_name: 'quality_critic',
      rejection_reason: String(j.critic.rejection_reason || 'Rejected by critic gate.').trim(),
      raw_output_json: JSON.stringify({ critic: j.critic, concept_thesis: j.symbolic_tension?.concept_thesis, mechanisms: j.abstraction?.abstraction_mechanisms, abstraction_target: j.abstraction?.abstraction_target }),
      created_at: now
    }
  }
}];
